CREATE TABLE app_settings (
  setting_key    VARCHAR(64)   PRIMARY KEY,
  setting_value  VARCHAR(2048) NOT NULL,
  updated_at     TIMESTAMPTZ   NOT NULL,
  updated_by     VARCHAR(255)  NULL
);

